export const getWordsByLevel = (level: Level): Word[] => {
  return words.filter(w => w.level === level);
};

export const getWordsByLevelAndCategory = (level: Level, category: WordCategory): Word[] => {
  return words.filter(w => w.level === level && w.category === category);
};

export const getCategoriesByLevel = (level: Level): WordCategory[] => {
  const categories = new Set(words.filter(w => w.level === level).map(w => w.category));
  return Array.from(categories) as WordCategory[];
};

export const getAllCategories = (): WordCategory[] => {
  const categories = new Set(words.map(w => w.category));
  return Array.from(categories) as WordCategory[];
};
